import { useState } from 'react';
import { Chip, Stack, Typography, Box, IconButton, Divider } from '@mui/material';
import EditIcon from '@mui/icons-material/Edit';
import SchoolIcon from '@mui/icons-material/School';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import BadgeIcon from '@mui/icons-material/Badge';
import StarIcon from '@mui/icons-material/Star';
import { ProfileServices } from '@/api/profiles.api';
import { CallStatus, Roles } from '@/types/api.types';
import { ProfileBasicResult } from '@/types/profile.types';
import { PageCard } from '@/components/PageCard';
import { StatusMessage } from '@/components/StatusMessage';
import { TabHeader } from '@/components/TabHeader';
import { InfiniteScrollList } from '@/components/InfiniteScrollList';
import { useInfiniteScroll } from '@/hooks/useInfiniteScroll';
import { compactChipSx } from '@/constants/ThemeConstants';
import UpdateRoleDialog, { RoleDialogProfile } from './components/UpdateRoleDialog';
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';

const getRoleColor = (role: string): 'secondary' | 'info' | 'primary' | 'default' => {
    switch (role) {
        case Roles.SuperAdmin: return 'secondary';
        case Roles.Admin: return 'secondary';
        case Roles.EventMgr: return 'info';
        default: return 'default';
    }
};

const getRoleVariant = (role: string): 'filled' | 'outlined' => {
    switch (role) {
        case Roles.SuperAdmin:
        case Roles.Admin:
            return 'filled';
        default:
            return 'outlined';
    }
};

// Returns a CSS color string for the left-accent border. Uses MUI brand-ish
// hex literals so the role-coded coloring stays consistent across themes.
const getAccentColor = (roles?: Roles[]): string => {
    if (!roles) return 'rgba(0,0,0,0.12)';
    if (roles.includes(Roles.SuperAdmin)) return '#9c27b0';
    if (roles.includes(Roles.Admin)) return '#9c27b0';
    if (roles.includes(Roles.EventMgr)) return '#0288d1';
    return '#1976d2';
};

export function ElevatedRolesList() {
    const [selectedProfile, setSelectedProfile] = useState<ProfileBasicResult | null>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [infoProfileId, setInfoProfileId] = useState<string | null>(null);

    const {
        items: profiles,
        loading,
        hasMore,
        loadMore,
        error,
        refresh
    } = useInfiniteScroll<ProfileBasicResult>({
        fetchFunction: ProfileServices.GetProfilesWithElevatedRoles,
        initialPageSize: 50,
        autoLoad: true
    });

    const handleEditRole = (profile: ProfileBasicResult) => {
        setSelectedProfile(profile);
        setIsDialogOpen(true);
    };

    const handleCloseDialog = () => {
        setIsDialogOpen(false);
        setSelectedProfile(null);
    };

    const handleRoleUpdateSuccess = (_updated: RoleDialogProfile) => {
        // Refresh the list to reflect updated roles
        refresh();
        handleCloseDialog();
    };

    const getStatus = (): CallStatus => {
        if (loading && profiles.length === 0) return CallStatus.InProgress;
        if (error) return CallStatus.Failure;
        return CallStatus.Success;
    };

    const status = getStatus();

    if (status !== CallStatus.Success || (status === CallStatus.Success && profiles.length === 0)) {
        return (
            <>
                <TabHeader
                    icon={<StarIcon color="primary" />}
                    title="Elevated roles"
                    subtitle="Users with Admin, SuperAdmin, EventMgr or other elevated roles."
                />
                <PageCard>
                    <StatusMessage
                        notStartedMessage="Loading elevated roles..."
                        successMessage={profiles.length === 0 ? "No users found with elevated roles." : ""}
                        failureMessage={error || "Failed to load elevated roles. Please try again."}
                        currentStatus={status}
                    />
                </PageCard>
            </>
        );
    }

    const renderProfileCard = (profile: ProfileBasicResult) => (
        <Box
            key={profile.id}
            sx={{
                p: 2,
                borderRadius: 2,
                bgcolor: 'background.paper',
                border: '1px solid',
                borderColor: 'divider',
                borderLeft: `4px solid ${getAccentColor(profile.roles)}`,
                transition: 'box-shadow 0.2s',
                '&:hover': { boxShadow: 2 },
            }}
        >
                {/* Name + Edit */}
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
                    <Typography
                        variant="subtitle1"
                        onClick={() => setInfoProfileId(profile.id)}
                        sx={{
                            fontWeight: 600,
                            color: 'primary.main',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            whiteSpace: 'nowrap',
                            cursor: 'pointer',
                            '&:hover': { textDecoration: 'underline' },
                        }}
                    >
                        {profile.name}
                    </Typography>
                    <IconButton size="small" onClick={() => handleEditRole(profile)} sx={{ bgcolor: 'primary.main', color: 'primary.contrastText', flexShrink: 0, ml: 1, width: 32, height: 32, '&:hover': { bgcolor: 'primary.dark' } }}>
                        <EditIcon sx={{ fontSize: '1rem' }} />
                    </IconButton>
                </Box>

                {/* Meta grid - 2 columns */}
                <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' }, gap: 0.5, mb: 1.5 }}>
                    {profile.firstJnvName && (
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                            <SchoolIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                            <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                {profile.firstJnvName}
                            </Typography>
                        </Box>
                    )}
                    {profile.batch > 0 && (
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                            <BadgeIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                            <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                Batch {profile.batch}
                            </Typography>
                        </Box>
                    )}
                    {profile.email && (
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, minWidth: 0 }}>
                            <EmailIcon sx={{ fontSize: '0.95rem', color: 'text.disabled', flexShrink: 0 }} />
                            <Typography variant="caption" sx={{ color: 'text.secondary', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                {profile.email}
                            </Typography>
                        </Box>
                    )}
                    {profile.phone && (
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                            <PhoneIcon sx={{ fontSize: '0.95rem', color: 'text.disabled' }} />
                            <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                                {profile.phone}
                            </Typography>
                        </Box>
                    )}
                </Box>

                <Divider sx={{ mb: 1, borderStyle: 'dashed' }} />

                {/* Roles */}
                <Stack direction="row" spacing={0.5} sx={{ flexWrap: 'wrap', gap: 0.5 }}>
                    {profile.roles && profile.roles.length > 0 ? (
                        profile.roles.map((role) => (
                            <Chip
                                key={role}
                                label={role}
                                size="small"
                                color={getRoleColor(role)}
                                variant={getRoleVariant(role)}
                                sx={{
                                    ...compactChipSx,
                                    ...(getRoleVariant(role) === 'filled' && {
                                        color: '#fff !important',
                                        '& .MuiChip-label': { color: '#fff' },
                                    }),
                                }}
                            />
                        ))
                    ) : (
                        <Typography variant="caption" sx={{ color: 'text.disabled' }}>No roles</Typography>
                    )}
                </Stack>
        </Box>
    );

    return (
        <>
            <TabHeader
                icon={<StarIcon color="primary" />}
                title="Elevated roles"
                subtitle="Users with Admin, SuperAdmin, EventMgr or other elevated roles."
            />
            <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 1, ml: 0.5 }}>
                {profiles.length} user{profiles.length !== 1 ? 's' : ''} with elevated roles
            </Typography>

            <InfiniteScrollList
                items={profiles}
                renderItem={renderProfileCard}
                loading={loading}
                hasMore={hasMore}
                loadMore={loadMore}
                error={error}
                onRetry={refresh}
                emptyMessage="No users found with elevated roles."
                containerSx={{ display: 'flex', flexDirection: 'column', gap: 1.5 }}
            />

            {selectedProfile && (
                <UpdateRoleDialog
                    open={isDialogOpen}
                    profile={selectedProfile}
                    onClose={handleCloseDialog}
                    onSuccess={handleRoleUpdateSuccess}
                />
            )}

            <ProfileInfoDialog
                open={!!infoProfileId}
                profileId={infoProfileId ?? ''}
                onClose={() => setInfoProfileId(null)}
            />
        </>
    );
}
